import React, { useState, useRef, useEffect } from 'react';
import { DocumentType } from './types';
import SignaturePad, { SignaturePadRef } from './components/SignaturePad';
import CameraModal from './components/CameraModal';
import ParticleBackground from './components/ParticleBackground';
import TermsModal from './components/TermsModal';
import ProcessingOverlay from './components/ProcessingOverlay';
import { jsPDF } from 'jspdf';

/**
 * CONFIGURACIÓN DE LA APLICACIÓN
 * 1. Cambia RECIPIENT_EMAIL por tu propio correo (solo afecta al mensaje de éxito).
 * 2. Configura EmailJS con tus llaves reales para que el envío funcione.
 * IMPORTANTE: Para que llegue a TU gmail, debes configurar el "To Email" en el dashboard de EmailJS.
 */
const APP_CONFIG = {
  RECIPIENT_EMAIL: "TU_GMAIL_AQUI@gmail.com", // Cambia esto por tu correo real
  EMAILJS: {
    PUBLIC_KEY: "TU_PUBLIC_KEY_AQUI",     
    SERVICE_ID: "TU_SERVICE_ID_AQUI",     
    TEMPLATE_ID: "TU_TEMPLATE_ID_AQUI"    
  }
};

declare var emailjs: any;

interface FormState {
  fullName: string;
  documentType: DocumentType | '';
  documentNumber: string;
  personalId: string;
  sociedadGestion: string;
  ipi: string;
  selfie?: File;
  documentFront?: File;
  documentBack?: File;
}

const InputField: React.FC<{ label: string; id: string; value: string; onChange: (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => void; type?: string; placeholder?: string }> = ({ label, id, ...props }) => (
    <div className="group">
        <label htmlFor={id} className="block text-[10px] font-black text-zinc-500 mb-2 uppercase tracking-[0.3em] group-focus-within:text-violet-400 transition-colors">
          {label}
        </label>
        <input 
          id={id} 
          name={id} 
          {...props} 
          className="uppercase w-full px-5 py-3.5 bg-zinc-900/60 border border-zinc-800 text-zinc-100 placeholder-zinc-700 rounded-2xl shadow-inner focus:ring-1 focus:ring-violet-500/50 focus:border-violet-500/50 transition-all outline-none" 
        />
    </div>
);

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormState>({
    fullName: '',
    documentType: '',
    documentNumber: '',
    personalId: '',
    sociedadGestion: '',
    ipi: '',
  });
  const [selfieFileName, setSelfieFileName] = useState('ESPERANDO CAPTURA');
  const [documentFrontFileName, setDocumentFrontFileName] = useState('ESPERANDO CAPTURA');
  const [documentBackFileName, setDocumentBackFileName] = useState('ESPERANDO CAPTURA');
  const [isSigned, setIsSigned] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [cameraFor, setCameraFor] = useState<'selfie' | 'documentFront' | 'documentBack' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const signaturePadRef = useRef<SignaturePadRef>(null);

  useEffect(() => {
    if (typeof emailjs !== 'undefined' && APP_CONFIG.EMAILJS.PUBLIC_KEY !== "TU_PUBLIC_KEY_AQUI") {
        emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY); 
    }
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prevState => ({ ...prevState, [name]: value.toUpperCase() }));
  };

  const openCamera = (type: 'selfie' | 'documentFront' | 'documentBack') => {
    setCameraFor(type);
    setIsCameraModalOpen(true);
  }

  const handleCapture = (imageFile: File) => {
    if (cameraFor === 'selfie') {
        setFormData(prevState => ({ ...prevState, selfie: imageFile }));
        setSelfieFileName('CAPTURA LISTA');
    } else if (cameraFor === 'documentFront') {
        setFormData(prevState => ({ ...prevState, documentFront: imageFile }));
        setDocumentFrontFileName('CAPTURA LISTA');
    } else if (cameraFor === 'documentBack') {
        setFormData(prevState => ({ ...prevState, documentBack: imageFile }));
        setDocumentBackFileName('CAPTURA LISTA');
    }
    setIsCameraModalOpen(false);
    setCameraFor(null);
  };

  const clearSignature = () => {
    signaturePadRef.current?.clear();
    setIsSigned(false);
  };

  const resetForm = () => {
    setFormData({
      fullName: '',
      documentType: '',
      documentNumber: '',
      personalId: '',
      sociedadGestion: '',
      ipi: '',
      selfie: undefined,
      documentFront: undefined,
      documentBack: undefined,
