  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentType || !formData.documentNumber || !formData.personalId || !formData.sociedadGestion || !formData.ipi || !formData.selfie || !formData.documentFront || !formData.documentBack || !signature) {
