      alert("ATENCIÓN: Debes configurar tus llaves de EmailJS en App.tsx para enviar correos reales.");
    }

    setIsProcessing(true);
    setProcessingStep('GENERANDO CREDENCIAL VIP...');

    try {
        const loadImage = (file: File): Promise<HTMLImageElement> => {
            return new Promise((resolve) => {
                const reader = new FileReader();
                reader.onload = (event) => {
                    const img = new Image();
                    img.onload = () => resolve(img);
                    img.src = event.target?.result as string;
                };
                reader.readAsDataURL(file);
            });
        };

        const [selfieImg, docFrontImg, docBackImg] = await Promise.all([
            loadImage(formData.selfie!),
            loadImage(formData.documentFront!),
            loadImage(formData.documentBack!),
        ]);

        const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
        const pdfWidth = doc.internal.pageSize.getWidth();
        const margin = 20;

        doc.setFillColor(10, 10, 12);
        doc.rect(0, 0, pdfWidth, 297, 'F');
        doc.setTextColor(240, 240, 245);
        doc.setFontSize(28);
        doc.text("SPACE TOWN", pdfWidth / 2, 25, { align: 'center' });
        doc.setDrawColor(76, 29, 149); // Violet Border
        doc.line(margin, 30, pdfWidth - margin, 30);

        let currentY = 50;
        doc.setFontSize(14);
        doc.text("REGISTRO DE ACCESO ARTISTA / VIP", margin, currentY);
        currentY += 15;

        const addField = (label: string, value: string) => {
            doc.setFontSize(9);
            doc.setTextColor(150, 150, 160);
            doc.text(label, margin, currentY);
            doc.setFontSize(11);
            doc.setTextColor(255, 255, 255);
            doc.text(value, margin + 65, currentY);
            currentY += 10;
        };

        addField("NOMBRE LEGAL:", formData.fullName);
        addField("IDENTIFICACIÓN:", `${formData.documentType} - ${formData.documentNumber}`);
        addField("A.K.A:", formData.personalId);
        addField("SOCIEDAD:", formData.sociedadGestion);
        addField("IPI:", formData.ipi);

        currentY += 10;
        doc.addImage(signature, 'PNG', margin, currentY, 60, 30);

        doc.addPage();
        doc.setFillColor(10, 10, 12);
        doc.rect(0, 0, pdfWidth, 297, 'F');
        doc.text("VERIFICACIÓN DE IDENTIDAD", margin, 25);
        doc.addImage(selfieImg, 'JPEG', margin, 40, 60, 60);
        doc.addImage(docFrontImg, 'JPEG', margin, 110, 100, 60);
        doc.addImage(docBackImg, 'JPEG', margin, 180, 100, 60);

        setProcessingStep('ENVIANDO A CENTRAL DE ACCESO...');

        const pdfBase64 = doc.output('datauristring');

        const templateParams = {
            user_name: formData.fullName,
            user_id: formData.documentNumber,
            user_aka: formData.personalId,
            content: pdfBase64 
        };

        if (typeof emailjs !== 'undefined' && APP_CONFIG.EMAILJS.SERVICE_ID !== "TU_SERVICE_ID_AQUI") {
            await emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, templateParams);
        } else {
            console.warn("Simulando envío. Configura EmailJS para recibirlo en " + APP_CONFIG.RECIPIENT_EMAIL);
            await new Promise(resolve => setTimeout(resolve, 2500));
        }

        setProcessingStep('¡ACCESO CONFIRMADO!');
        await new Promise(resolve => setTimeout(resolve, 800));

        setIsProcessing(false);
        setShowSuccess(true);

    } catch (error) {
        console.error("Error completo:", error);
        alert("Ocurrió un error al enviar el registro. Verifica tu conexión o configuración de EmailJS.");
        setIsProcessing(false);
    }
  };

  if (showSuccess) {
    return (
      <div className="min-h-screen flex items-center justify-center p-8 text-center bg-zinc-950">
        <div className="max-w-md w-full p-12 bg-zinc-900 border border-violet-900/30 rounded-[3rem] shadow-[0_0_50px_rgba(139,92,246,0.15)]">
          <div className="w-20 h-20 bg-violet-600 rounded-full flex items-center justify-center mx-auto mb-8 shadow-[0_0_40px_rgba(139,92,246,0.5)] animate-pulse">
            <span className="text-4xl text-white font-bold">✓</span>
          </div>
          <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter">Acceso Autorizado</h2>
          <p className="text-zinc-400 text-[10px] mb-10 leading-relaxed font-bold uppercase tracking-[0.2em]">
            Tu registro ha sido enviado exitosamente a <b className="text-violet-400">{APP_CONFIG.RECIPIENT_EMAIL}</b>.<br/>
            El equipo de seguridad procesará tu solicitud en breve.
          </p>
          <button 
            onClick={resetForm}
            className="w-full py-4 text-white font-black bg-violet-600 rounded-2xl hover:bg-violet-500 transition-all uppercase tracking-tighter shadow-xl transform active:scale-95"
          >
