          <div className="max-w-5xl w-full mx-auto bg-black/80 backdrop-blur-3xl border border-zinc-800 p-10 sm:p-16 rounded-[3.5rem] shadow-[0_50px_100px_-20px_rgba(0,0,0,0.9)]">
            <header className="text-center mb-16">
              <span className="inline-block px-4 py-1.5 bg-violet-900/20 text-[9px] font-black text-violet-400 rounded-full mb-4 tracking-[0.4em] border border-violet-900/30">
