                      name="documentType" 
                      value={formData.documentType} 
                      onChange={handleChange}
                      className="w-full px-5 py-3.5 bg-zinc-900/60 border border-zinc-800 text-zinc-100 rounded-2xl focus:ring-1 focus:ring-violet-500/50 transition-all outline-none appearance-none font-bold uppercase"
                    >
                      <option value="" disabled>SELECCIONE...</option>
                      {Object.values(DocumentType).map((type) => (
                        <option key={type} value={type} className="bg-zinc-900">{type.toUpperCase()}</option>
                      ))}
                    </select>
                    <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none text-violet-500/50">▼</div>
                  </div>
                </div>

                <InputField label="Número ID" id="documentNumber" value={formData.documentNumber} onChange={handleChange} placeholder="00000000" />
                <InputField label="A.K.A Artista" id="personalId" value={formData.personalId} onChange={handleChange} placeholder="EJ: TITANIUM" />
                <InputField label="S. Gestión" id="sociedadGestion" value={formData.sociedadGestion} onChange={handleChange} placeholder="SAYCO / ACINPRO" />
                <InputField label="Código IPI" id="ipi" value={formData.ipi} onChange={handleChange} placeholder="000000000" />

                <div className="md:col-span-2 grid grid-cols-1 sm:grid-cols-3 gap-8">
                  {[
                    { type: 'selfie', label: 'Face Recognition', file: selfieFileName },
                    { type: 'documentFront', label: 'ID Front Scan', file: documentFrontFileName },
                    { type: 'documentBack', label: 'ID Back Scan', file: documentBackFileName }
                  ].map((item) => (
                    <div key={item.type} className="flex flex-col">
                      <label className="text-[9px] font-black text-zinc-600 mb-3 uppercase tracking-[0.4em] text-center">{item.label}</label>
                      <button 
                        type="button" 
                        onClick={() => openCamera(item.type as any)} 
                        className="group relative w-full py-5 bg-zinc-900/40 border border-zinc-800 rounded-[1.5rem] hover:border-violet-500 transition-all overflow-hidden"
                      >
                        <span className="relative z-10 text-[10px] font-black text-zinc-500 group-hover:text-white transition-colors tracking-widest uppercase">Escanear</span>
                        <div className="absolute inset-0 bg-gradient-to-tr from-violet-900/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                      </button>
                      <p className="mt-3 text-[8px] text-violet-400 truncate text-center font-black uppercase tracking-tighter">{item.file}</p>
                    </div>
                  ))}
