                <div className="md:col-span-2">
                  <label className="block text-[10px] font-black text-zinc-500 mb-4 uppercase tracking-[0.3em]">Firma de Seguridad</label>
                  <div className="w-full h-48 bg-black/60 border border-zinc-800 rounded-[2.5rem] relative overflow-hidden group shadow-[inset_0_4px_20px_rgba(0,0,0,0.8)] focus-within:border-violet-500/50 transition-colors">
                    {!isSigned && (
