              <p className="text-[9px] font-bold text-violet-400 tracking-[0.6em] uppercase opacity-80">Artist Registration System</p>
            </header>

            <form onSubmit={handleSubmit} className="space-y-10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <InputField label="Nombre Legal" id="fullName" value={formData.fullName} onChange={handleChange} placeholder="NOMBRE COMPLETO" />

                <div className="group">
                  <label htmlFor="documentType" className="block text-[9px] font-black text-zinc-500 mb-2 uppercase tracking-[0.4em]">Tipo ID</label>
