          className="uppercase w-full px-5 py-4 bg-zinc-900/40 border border-zinc-800/50 text-white placeholder-zinc-700 rounded-xl focus:border-violet-500/50 focus:ring-1 focus:ring-violet-500/20 transition-all outline-none font-bold tracking-wider" 
        />
        <div className="absolute bottom-0 left-0 h-[1px] w-0 bg-violet-500 group-focus-within:w-full transition-all duration-500"></div>
    </div>
);

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormState>({
    fullName: '',
    documentType: '',
    documentNumber: '',
    personalId: '',
    sociedadGestion: '',
    ipi: '',
  });
  const [selfieFileName, setSelfieFileName] = useState('NO DATA');
  const [documentFrontFileName, setDocumentFrontFileName] = useState('NO DATA');
  const [documentBackFileName, setDocumentBackFileName] = useState('NO DATA');
  const [isSigned, setIsSigned] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [cameraFor, setCameraFor] = useState<'selfie' | 'documentFront' | 'documentBack' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const signaturePadRef = useRef<SignaturePadRef>(null);

  useEffect(() => {
    if (typeof emailjs !== 'undefined' && APP_CONFIG.EMAILJS.PUBLIC_KEY !== "TU_PUBLIC_KEY_AQUI") {
        emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY); 
    }
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prevState => ({ ...prevState, [name]: value.toUpperCase() }));
  };

  const openCamera = (type: 'selfie' | 'documentFront' | 'documentBack') => {
    playInterfaceSound('click');
    setCameraFor(type);
    setIsCameraModalOpen(true);
  }

  const handleCapture = (imageFile: File) => {
    playInterfaceSound('scan');
    if (cameraFor === 'selfie') {
        setFormData(prevState => ({ ...prevState, selfie: imageFile }));
        setSelfieFileName('BIO-DATA STORED');
    } else if (cameraFor === 'documentFront') {
        setFormData(prevState => ({ ...prevState, documentFront: imageFile }));
        setDocumentFrontFileName('DOC-FRONT STORED');
    } else if (cameraFor === 'documentBack') {
        setFormData(prevState => ({ ...prevState, documentBack: imageFile }));
        setDocumentBackFileName('DOC-BACK STORED');
    }
    setIsCameraModalOpen(false);
    setCameraFor(null);
  };

  const clearSignature = () => {
    playInterfaceSound('click');
    signaturePadRef.current?.clear();
    setIsSigned(false);
  };

  const resetForm = () => {
    setFormData({
      fullName: '',
      documentType: '',
      documentNumber: '',
      personalId: '',
      sociedadGestion: '',
      ipi: '',
    });
    setSelfieFileName('NO DATA');
    setDocumentFrontFileName('NO DATA');
    setDocumentBackFileName('NO DATA');
    setIsSigned(false);
    setShowSuccess(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentNumber || !formData.selfie || !signature) {
      alert('REQUERIMIENTOS DE SEGURIDAD INCOMPLETOS.');
      return;
    }

    setIsProcessing(true);
    setProcessingStep('GENERANDO CREDENCIAL VIP...');

    try {
        const loadImage = (file: File): Promise<HTMLImageElement> => {
            return new Promise((resolve) => {
                const reader = new FileReader();
                reader.onload = (event) => {
                    const img = new Image();
                    img.onload = () => resolve(img);
                    img.src = event.target?.result as string;
                };
                reader.readAsDataURL(file);
            });
        };

        const [selfieImg, docFrontImg, docBackImg] = await Promise.all([
            loadImage(formData.selfie!),
            loadImage(formData.documentFront!),
            loadImage(formData.documentBack!),
        ]);

        const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
        const pdfWidth = doc.internal.pageSize.getWidth();

        // Diseño PDF "Dark Mode VIP"
        doc.setFillColor(5, 5, 5);
        doc.rect(0, 0, pdfWidth, 297, 'F');

        doc.setDrawColor(139, 92, 246);
        doc.setLineWidth(0.5);
        doc.rect(10, 10, pdfWidth - 20, 277);

        doc.setTextColor(139, 92, 246);
        doc.setFontSize(32);
        doc.text("SPACE TOWN", pdfWidth / 2, 35, { align: 'center' });

        doc.setTextColor(255, 255, 255);
        doc.setFontSize(10);
        doc.text("VIP ARTIST CLEARANCE", pdfWidth / 2, 45, { align: 'center' });

        let y = 70;
        const addInfo = (label: string, value: string) => {
            doc.setFontSize(8);
            doc.setTextColor(100, 100, 100);
            doc.text(label.toUpperCase(), 25, y);
            doc.setFontSize(12);
            doc.setTextColor(255, 255, 255);
            doc.text(value.toUpperCase(), 25, y + 6);
            y += 20;
        };

        addInfo("Nombre Completo", formData.fullName);
        addInfo("ID / Pasaporte", `${formData.documentType} ${formData.documentNumber}`);
        addInfo("Alias Artístico", formData.personalId);
        addInfo("Sociedad de Gestión", formData.sociedadGestion);
        addInfo("Código IPI", formData.ipi);

        doc.addImage(signature, 'PNG', 25, y, 60, 25);
        doc.setFontSize(7);
        doc.text("FIRMA ELECTRÓNICA REGISTRADA", 25, y + 30);

        doc.addPage();
        doc.setFillColor(5, 5, 5);
        doc.rect(0, 0, pdfWidth, 297, 'F');
        doc.setTextColor(139, 92, 246);
        doc.text("VERIFICACIÓN BIO-MÉTRICA", 20, 20);

        doc.addImage(selfieImg, 'JPEG', 20, 30, 80, 80);
        doc.addImage(docFrontImg, 'JPEG', 20, 120, 110, 70);
        doc.addImage(docBackImg, 'JPEG', 20, 200, 110, 70);

        setProcessingStep('SINCRONIZANDO CON CENTRAL...');

        const pdfBase64 = doc.output('datauristring');

        if (typeof emailjs !== 'undefined' && APP_CONFIG.EMAILJS.SERVICE_ID !== "TU_SERVICE_ID_AQUI") {
            await emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
                user_name: formData.fullName,
                content: pdfBase64 
            });
        } else {
            await new Promise(resolve => setTimeout(resolve, 3000));
        }

        setProcessingStep('ACCESO GARANTIZADO');
        await new Promise(resolve => setTimeout(resolve, 1000));

        setIsProcessing(false);
        setShowSuccess(true);

    } catch (error) {
        alert("ERROR EN LA TRANSMISIÓN. REINTENTE.");
        setIsProcessing(false);
    }
  };

  if (showSuccess) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-black font-orbitron">
