import React, { useState, useRef, useEffect } from 'react';
import { DocumentType } from './types';
import SignaturePad, { SignaturePadRef } from './components/SignaturePad';
import CameraModal from './components/CameraModal';
import ParticleBackground from './components/ParticleBackground';
import TermsModal from './components/TermsModal';
import ProcessingOverlay from './components/ProcessingOverlay';
import { jsPDF } from 'jspdf';

// CONFIGURACIÓN DE ACCESO
const APP_CONFIG = {
  RECIPIENT_EMAIL: "appspacetown@gmail.com", 
  EMAILJS: {
    PUBLIC_KEY: "TU_PUBLIC_KEY_AQUI", // RECUERDA PONER TU LLAVE PÚBLICA AQUÍ
    SERVICE_ID: "service_n97bgi4",     
    TEMPLATE_ID: "TU_TEMPLATE_ID_AQUI" // RECUERDA PONER TU ID DE PLANTILLA AQUÍ
  }
};

declare var emailjs: any;

interface FormState {
  fullName: string;
  documentType: DocumentType | '';
  documentNumber: string;
  personalId: string;
  sociedadGestion: string;
  ipi: string;
  selfie?: File;
  documentFront?: File;
  documentBack?: File;
}

const playInterfaceSound = (type: 'click' | 'success' | 'scan') => {
  try {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);

    if (type === 'click') {
      osc.frequency.setValueAtTime(800, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.1);
      osc.start(); osc.stop(ctx.currentTime + 0.1);
    } else if (type === 'scan') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(150, ctx.currentTime);
      osc.frequency.linearRampToValueAtTime(1200, ctx.currentTime + 0.3);
      gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.3);
      osc.start(); osc.stop(ctx.currentTime + 0.3);
    }
  } catch (e) { /* Audio fails silently if blocked */ }
};

const InputField: React.FC<{ label: string; id: string; value: string; onChange: (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => void; placeholder?: string }> = ({ label, id, ...props }) => (
    <div className="group relative">
        <label htmlFor={id} className="block text-[9px] font-black text-zinc-500 mb-2 uppercase tracking-[0.4em] group-focus-within:text-violet-400 transition-colors">
          {label}
        </label>
        <input 
          id={id} name={id} autoComplete="off" {...props} 
          onFocus={() => playInterfaceSound('click')}
          className="uppercase w-full px-5 py-4 bg-zinc-900/40 border border-zinc-800/50 text-white placeholder-zinc-700 rounded-xl focus:border-violet-500/50 focus:ring-1 focus:ring-violet-500/20 transition-all outline-none font-bold tracking-wider" 
        />
    </div>
);

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormState>({
    fullName: '', documentType: '', documentNumber: '', personalId: '', sociedadGestion: '', ipi: '',
  });
  const [isSigned, setIsSigned] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [cameraFor, setCameraFor] = useState<'selfie' | 'documentFront' | 'documentBack' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const signaturePadRef = useRef<SignaturePadRef>(null);

  useEffect(() => {
    if (typeof emailjs !== 'undefined' && APP_CONFIG.EMAILJS.PUBLIC_KEY !== "TU_PUBLIC_KEY_AQUI") {
        emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY); 
    }
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prevState => ({ ...prevState, [name]: value.toUpperCase() }));
  };

  const openCamera = (type: 'selfie' | 'documentFront' | 'documentBack') => {
    playInterfaceSound('click');
    setCameraFor(type);
    setIsCameraModalOpen(true);
  }

  const handleCapture = (imageFile: File) => {
    playInterfaceSound('scan');
    setFormData(prevState => ({ ...prevState, [cameraFor!]: imageFile }));
    setIsCameraModalOpen(false);
    setCameraFor(null);
  };

  const clearSignature = () => {
    playInterfaceSound('click');
    signaturePadRef.current?.clear();
    setIsSigned(false);
  };

  const resetForm = () => {
    setFormData({ fullName: '', documentType: '', documentNumber: '', personalId: '', sociedadGestion: '', ipi: '' });
    setIsSigned(false);
    setShowSuccess(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentNumber || !formData.selfie || !formData.documentFront || !formData.documentBack || !signature) {
      alert('POR FAVOR: Capture las 3 fotos y firme para continuar.');
      return;
    }

    setIsProcessing(true);
    setProcessingStep('ENCRIPTANDO DATOS BIOMÉTRICOS...');

    try {
        const loadImage = (file: File): Promise<HTMLImageElement> => {
            return new Promise((resolve) => {
                const reader = new FileReader();
                reader.onload = (event) => {
                    const img = new Image();
                    img.onload = () => resolve(img);
                    img.src = event.target?.result as string;
                };
                reader.readAsDataURL(file);
            });
        };

        const [selfieImg, docFrontImg, docBackImg] = await Promise.all([
            loadImage(formData.selfie!),
            loadImage(formData.documentFront!),
            loadImage(formData.documentBack!),
        ]);

        const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
        const pdfWidth = doc.internal.pageSize.getWidth();

        doc.setFillColor(5, 5, 5);
        doc.rect(0, 0, pdfWidth, 297, 'F');
        doc.setDrawColor(139, 92, 246);
        doc.setLineWidth(0.5);
        doc.rect(10, 10, pdfWidth - 20, 277);

        doc.setTextColor(139, 92, 246);
        doc.setFontSize(32);
        doc.text("SPACE TOWN", pdfWidth / 2, 35, { align: 'center' });

        doc.setTextColor(255, 255, 255);
        doc.setFontSize(10);
        doc.text("VIP ARTIST CLEARANCE", pdfWidth / 2, 45, { align: 'center' });

        let y = 70;
        const addInfo = (label: string, value: string) => {
            doc.setFontSize(8); doc.setTextColor(100, 100, 100);
            doc.text(label.toUpperCase(), 25, y);
            doc.setFontSize(12); doc.setTextColor(255, 255, 255);
            doc.text(value.toUpperCase(), 25, y + 6);
            y += 20;
        };

        addInfo("Nombre Completo", formData.fullName);
        addInfo("ID / Pasaporte", `${formData.documentType} ${formData.documentNumber}`);
        addInfo("Alias Artístico", formData.personalId);
        addInfo("Sociedad de Gestión", formData.sociedadGestion);
        addInfo("Código IPI", formData.ipi);

        doc.addImage(signature, 'PNG', 25, y, 60, 25);
        doc.addPage();
        doc.setFillColor(5, 5, 5); doc.rect(0, 0, pdfWidth, 297, 'F');
        doc.setTextColor(139, 92, 246); doc.text("VERIFICACIÓN BIO-MÉTRICA", 20, 20);
        doc.addImage(selfieImg, 'JPEG', 20, 30, 80, 80);
        doc.addImage(docFrontImg, 'JPEG', 20, 120, 110, 70);
        doc.addImage(docBackImg, 'JPEG', 20, 200, 110, 70);

        setProcessingStep('TRANSMITIENDO A GMAIL...');

        const pdfBase64 = doc.output('datauristring');

        if (typeof emailjs !== 'undefined' && APP_CONFIG.EMAILJS.SERVICE_ID !== "TU_SERVICE_ID_AQUI") {
            await emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
                user_name: formData.fullName,
                content: pdfBase64 
            });
        } else {
            await new Promise(resolve => setTimeout(resolve, 3000));
        }

        setProcessingStep('REGISTRO FINALIZADO');
        await new Promise(resolve => setTimeout(resolve, 1000));
        setIsProcessing(false); setShowSuccess(true);

    } catch (error) {
        alert("ERROR EN LA TRANSMISIÓN. REINTENTE.");
        setIsProcessing(false);
    }
  };

  const CaptureButton: React.FC<{ type: 'selfie' | 'documentFront' | 'documentBack', label: string }> = ({ type, label }) => {
    const isCaptured = !!formData[type];
    return (
      <button 
        type="button" onClick={() => openCamera(type)} 
        className={`flex flex-col items-center p-6 border transition-all group active:scale-95 rounded-2xl ${
          isCaptured 
            ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_20px_rgba(34,211,238,0.2)]' 
            : 'bg-zinc-900/30 border-zinc-800 hover:border-violet-500/50'
        }`}
      >
        <span className={`text-[8px] font-black mb-3 tracking-widest uppercase ${isCaptured ? 'text-cyan-400' : 'text-zinc-600 group-hover:text-violet-400'}`}>
          {label}
        </span>
        <div className={`w-12 h-12 border-2 rounded-full flex items-center justify-center mb-3 transition-all ${
          isCaptured 
            ? 'border-cyan-400 bg-cyan-400 shadow-[0_0_15px_rgba(34,211,238,0.5)]' 
            : 'border-dashed border-zinc-700 group-hover:border-violet-500 group-hover:rotate-90'
        }`}>
          {isCaptured ? (
            <svg className="w-6 h-6 text-black" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7"></path></svg>
          ) : (
            <span className="text-xl text-zinc-700 group-hover:text-violet-500">+</span>
          )}
        </div>
        <span className={`text-[7px] font-bold uppercase tracking-tighter ${isCaptured ? 'text-cyan-300' : 'text-violet-400'}`}>
          {isCaptured ? '✓ CAPTURED & READY' : 'WAITING FOR DATA'}
        </span>
      </button>
    );
  };

  if (showSuccess) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-black font-orbitron">
        <div className="max-w-md w-full p-10 bg-zinc-900/50 border-2 border-violet-500 rounded-[2rem] text-center shadow-[0_0_50px_rgba(139,92,246,0.2)]">
          <div className="w-24 h-24 bg-violet-600 rounded-full flex items-center justify-center mx-auto mb-8 shadow-[0_0_30px_rgba(139,92,246,0.6)]">
            <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
          </div>
          <h2 className="text-3xl font-black text-white mb-4 tracking-tighter uppercase neon-text">Access Granted</h2>
          <p className="text-zinc-500 text-[10px] mb-8 leading-relaxed tracking-widest uppercase">
            Registro enviado a {APP_CONFIG.RECIPIENT_EMAIL}. Revisa tu bandeja de entrada.
          </p>
          <button onClick={resetForm} className="w-full py-4 bg-white text-black font-black rounded-xl hover:bg-violet-500 hover:text-white transition-all uppercase tracking-widest text-xs">
            Nueva Sesión
          </button>
        </div>
      </div>
    );
  }

  return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      {!termsAccepted ? (
        <TermsModal onAccept={() => setTermsAccepted(true)} />
      ) : (
        <div className="min-h-screen flex items-center justify-center p-4 sm:p-12">
          <div className="max-w-4xl w-full bg-zinc-950/80 backdrop-blur-xl border border-zinc-800 p-8 sm:p-14 rounded-[3rem] shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 left-1/2 -translate-x-1/2 w-32 h-[2px] bg-violet-500 shadow-[0_0_15px_#8b5cf6]"></div>

            <header className="text-center mb-12">
              <h1 className="text-4xl sm:text-6xl font-black font-orbitron text-white uppercase tracking-[-0.05em] mb-2 neon-text">Space Town</h1>
              <p className="text-[9px] font-bold text-violet-400 tracking-[0.6em] uppercase opacity-80">Artist Registration System</p>
            </header>

            <form onSubmit={handleSubmit} className="space-y-10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <InputField label="Nombre Legal" id="fullName" value={formData.fullName} onChange={handleChange} placeholder="NOMBRE COMPLETO" />
