                    <option value="" disabled>SELECT TYPE</option>
                    {Object.values(DocumentType).map((type) => (
                      <option key={type} value={type} className="bg-zinc-950">{type.toUpperCase()}</option>
                    ))}
                  </select>
                </div>
                <InputField label="Número ID" id="documentNumber" value={formData.documentNumber} onChange={handleChange} placeholder="ID NUMBER" />
                <InputField label="A.K.A Artista" id="personalId" value={formData.personalId} onChange={handleChange} placeholder="STAGE NAME" />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                <CaptureButton type="selfie" label="Biometric Scan" />
                <CaptureButton type="documentFront" label="ID Front" />
                <CaptureButton type="documentBack" label="ID Rear" />
              </div>

              <div className="space-y-4">
                <label className="block text-[9px] font-black text-zinc-500 uppercase tracking-[0.4em]">Digital Signature</label>
                <div className="h-44 bg-black/50 border border-zinc-800 rounded-2xl relative neon-border overflow-hidden">
                  <SignaturePad ref={signaturePadRef} onDrawStart={() => setIsSigned(true)} />
                  {!isSigned && <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-[9px] text-zinc-800 font-black uppercase tracking-[0.8em]">Sign Here</div>}
                </div>
              </div>

              <div className="flex flex-col sm:flex-row items-center justify-between gap-6 pt-6">
                <button type="button" onClick={clearSignature} className="text-[9px] font-black text-zinc-700 hover:text-red-500 transition-colors uppercase tracking-widest">Clear Sign</button>
                <button
                  type="submit" disabled={isProcessing}
                  className="w-full sm:w-auto px-16 py-5 bg-violet-600 text-white font-black font-orbitron rounded-xl shadow-[0_15px_30px_rgba(139,92,246,0.3)] hover:bg-violet-500 hover:shadow-[0_15px_40px_rgba(139,92,246,0.5)] transition-all transform active:scale-95 uppercase tracking-widest"
