    fullName: '', documentType: '', documentNumber: '', personalId: '', sociedadGestion: '', ipi: '',
  });
  const [isSigned, setIsSigned] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [cameraFor, setCameraFor] = useState<'selfie' | 'documentFront' | 'documentBack' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const signaturePadRef = useRef<SignaturePadRef>(null);

  useEffect(() => {
    if (typeof emailjs !== 'undefined' && APP_CONFIG.EMAILJS.PUBLIC_KEY !== "TU_PUBLIC_KEY_AQUI") {
        emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY); 
    }
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prevState => ({ ...prevState, [name]: value.toUpperCase() }));
  };

  const openCamera = (type: 'selfie' | 'documentFront' | 'documentBack') => {
    playInterfaceSound('click');
    setCameraFor(type);
    setIsCameraModalOpen(true);
  }

  const handleCapture = (imageFile: File) => {
    playInterfaceSound('scan');
    setFormData(prevState => ({ ...prevState, [cameraFor!]: imageFile }));
    setIsCameraModalOpen(false);
    setCameraFor(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentNumber || !formData.selfie || !formData.documentFront || !formData.documentBack || !signature) {
      alert('DEBES COMPLETAR TODO: 3 Fotos, Datos y Firma.');
      return;
    }

    setIsProcessing(true);
    setProcessingStep('GENERANDO PDF SEGURO...');

    try {
        const loadImage = (file: File): Promise<HTMLImageElement> => {
            return new Promise((resolve) => {
                const reader = new FileReader();
                reader.onload = (event) => {
                    const img = new Image();
                    img.onload = () => resolve(img);
                    img.src = event.target?.result as string;
                };
                reader.readAsDataURL(file);
            });
        };

        const [selfieImg, docFrontImg, docBackImg] = await Promise.all([
            loadImage(formData.selfie!),
            loadImage(formData.documentFront!),
            loadImage(formData.documentBack!),
        ]);

        const doc = new jsPDF();
        const pdfWidth = doc.internal.pageSize.getWidth();

        // Estética PDF Negra Space Town
        doc.setFillColor(5, 5, 5); doc.rect(0, 0, pdfWidth, 297, 'F');
        doc.setTextColor(139, 92, 246); doc.setFontSize(28);
        doc.text("SPACE TOWN VIP", pdfWidth / 2, 30, { align: 'center' });

        doc.setTextColor(255, 255, 255); doc.setFontSize(12);
        doc.text(`ARTISTA: ${formData.fullName}`, 20, 50);
        doc.text(`ID: ${formData.documentNumber}`, 20, 60);
        doc.text(`AKA: ${formData.personalId}`, 20, 70);

        doc.addImage(signature, 'PNG', 20, 80, 50, 20);
        doc.addPage();
        doc.setFillColor(5, 5, 5); doc.rect(0, 0, pdfWidth, 297, 'F');
        doc.addImage(selfieImg, 'JPEG', 20, 20, 70, 70);
        doc.addImage(docFrontImg, 'JPEG', 20, 100, 100, 60);
        doc.addImage(docBackImg, 'JPEG', 20, 170, 100, 60);

        setProcessingStep('ENVIANDO A appspacetown@gmail.com...');

        const pdfBase64 = doc.output('datauristring');

        if (typeof emailjs !== 'undefined' && APP_CONFIG.EMAILJS.TEMPLATE_ID !== "TU_TEMPLATE_ID_AQUI") {
            await emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
                user_name: formData.fullName,
                content: pdfBase64 
            });
        } else {
            // Modo demo si no hay llaves
            await new Promise(r => setTimeout(r, 2000));
        }

        setIsProcessing(false); setShowSuccess(true);
    } catch (error) {
        alert("ERROR EN EL ENVÍO.");
        setIsProcessing(false);
    }
  };

  const CaptureButton: React.FC<{ type: 'selfie' | 'documentFront' | 'documentBack', label: string }> = ({ type, label }) => {
    const isCaptured = !!formData[type];
    return (
      <button 
        type="button" onClick={() => openCamera(type)} 
        className={`flex flex-col items-center p-6 border transition-all rounded-2xl ${
          isCaptured ? 'bg-cyan-950/20 border-cyan-500 shadow-[0_0_15px_rgba(34,211,238,0.3)]' : 'bg-zinc-900/30 border-zinc-800'
        }`}
      >
        <span className={`text-[8px] font-black mb-3 tracking-widest uppercase ${isCaptured ? 'text-cyan-400' : 'text-zinc-600'}`}>{label}</span>
        <div className={`w-12 h-12 border-2 rounded-full flex items-center justify-center mb-3 ${isCaptured ? 'border-cyan-400 bg-cyan-400' : 'border-dashed border-zinc-700'}`}>
          {isCaptured ? (
            <svg className="w-6 h-6 text-black" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7"></path></svg>
          ) : (
            <span className="text-xl text-zinc-700">+</span>
          )}
        </div>
        <span className={`text-[7px] font-bold uppercase ${isCaptured ? 'text-cyan-300' : 'text-violet-400'}`}>
          {isCaptured ? '✓ FOTO GUARDADA' : 'PENDIENTE'}
        </span>
      </button>
    );
  };

  if (showSuccess) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-black font-orbitron">
        <div className="max-w-md w-full p-10 bg-zinc-900/50 border-2 border-violet-500 rounded-[2rem] text-center">
          <div className="w-20 h-20 bg-violet-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
          </div>
          <h2 className="text-2xl font-black text-white mb-4 uppercase neon-text">Access Granted</h2>
          <p className="text-zinc-500 text-[10px] mb-8 uppercase tracking-widest">Enviado a {APP_CONFIG.RECIPIENT_EMAIL}</p>
          <button onClick={() => window.location.reload()} className="w-full py-4 bg-white text-black font-black rounded-xl uppercase tracking-widest text-xs">Finalizar</button>
        </div>
      </div>
    );
  }

  return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      {!termsAccepted ? <TermsModal onAccept={() => setTermsAccepted(true)} /> : (
        <div className="min-h-screen flex items-center justify-center p-4">
          <div className="max-w-4xl w-full bg-zinc-950/80 backdrop-blur-xl border border-zinc-800 p-8 sm:p-14 rounded-[3rem] shadow-2xl relative">
            <header className="text-center mb-12">
              <h1 className="text-4xl sm:text-6xl font-black font-orbitron text-white uppercase neon-text">Space Town</h1>
              <p className="text-[9px] font-bold text-violet-400 tracking-[0.6em] uppercase">VIP Artist Registration</p>
            </header>
            <form onSubmit={handleSubmit} className="space-y-10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <InputField label="Nombre Legal" id="fullName" value={formData.fullName} onChange={handleChange} />
                <div className="group">
                  <label className="block text-[9px] font-black text-zinc-500 mb-2 uppercase tracking-[0.4em]">Tipo ID</label>
                  <select name="documentType" value={formData.documentType} onChange={handleChange} className="w-full px-5 py-4 bg-zinc-900/40 border border-zinc-800 text-white rounded-xl outline-none font-bold">
                    <option value="" disabled>SELECT TYPE</option>
                    {Object.values(DocumentType).map((type) => <option key={type} value={type}>{type.toUpperCase()}</option>)}
                  </select>
                </div>
                <InputField label="Número ID" id="documentNumber" value={formData.documentNumber} onChange={handleChange} />
                <InputField label="A.K.A Artista" id="personalId" value={formData.personalId} onChange={handleChange} />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                <CaptureButton type="selfie" label="Selfie Biometric" />
                <CaptureButton type="documentFront" label="ID Front" />
                <CaptureButton type="documentBack" label="ID Rear" />
              </div>
              <div className="space-y-4">
                <label className="block text-[9px] font-black text-zinc-500 uppercase tracking-[0.4em]">Firma Digital</label>
                <div className="h-44 bg-black/50 border border-zinc-800 rounded-2xl relative overflow-hidden">
                  <SignaturePad ref={signaturePadRef} onDrawStart={() => setIsSigned(true)} />
                </div>
              </div>
              <button type="submit" className="w-full py-5 bg-violet-600 text-white font-black font-orbitron rounded-xl uppercase tracking-widest shadow-xl">Solicitar Acceso</button>
            </form>
          </div>
        </div>
      )}
      <CameraModal isOpen={isCameraModalOpen} onClose={() => setIsCameraModalOpen(false)} onCapture={handleCapture} purpose={cameraFor} />
    </>
  );
};

export default App;

