                download_link: downloadLink
            });
        }

        // Descarga automática en el móvil del usuario
        doc.save(`SPACETOWN_${formData.fullName}.pdf`);

        setIsProcessing(false); setShowSuccess(true);
        playInterfaceSound('success');
    } catch (error) {
