    if (savedStart) {
      setSessionStartTime(parseInt(savedStart));
      setFormData(prev => ({ ...prev, fullName: savedName || '', documentNumber: savedDoc || '' }));
      setLastPdfLink(savedLink || '');
      setTermsAccepted(true);
    }

    if (typeof emailjs !== 'undefined') {
        emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY); 
    }
  }, []);

  // Actualizar cronómetro cada segundo
  useEffect(() => {
    let interval: number;
    if (sessionStartTime) {
      interval = window.setInterval(() => {
        setElapsedTime(Math.floor((Date.now() - sessionStartTime) / 1000));
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [sessionStartTime]);

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
