    }
    return () => clearInterval(interval);
  }, [sessionStartTime]);

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prevState => ({ ...prevState, [name]: value.toUpperCase() }));
  };

  const openCamera = (type: 'selfie' | 'documentFront' | 'documentBack') => {
    setCameraFor(type);
    setIsCameraModalOpen(true);
  };

  const handleCapture = (imageFile: File) => {
    setFormData(prevState => ({ ...prevState, [cameraFor!]: imageFile }));
    setIsCameraModalOpen(false);
  };

  const uploadToCloud = async (pdfBlob: Blob): Promise<string> => {
    try {
      const uploadFormData = new FormData();
      uploadFormData.append('file', pdfBlob, 'acuerdo_spacetown.pdf');
      const response = await fetch('https://tmpfiles.org/api/v1/upload', {
        method: 'POST',
        body: uploadFormData
      });
      const result = await response.json();
      if (result.status === 'success' && result.data && result.data.url) {
        return result.data.url.replace('tmpfiles.org/', 'tmpfiles.org/dl/');
      }
      throw new Error("Upload fail");
    } catch (err) {
      return "ERROR_LINK";
    }
  };

  const addPdfDeco = (doc: jsPDF, pageNumber: number) => {
    const pdfWidth = doc.internal.pageSize.getWidth();
    const pdfHeight = doc.internal.pageSize.getHeight();

    // Barra lateral decorativa (derecha)
    doc.setFillColor(20, 20, 20);
    doc.rect(pdfWidth - 25, 0, 25, pdfHeight, 'F');

    // Texto lateral vertical
    doc.setTextColor(60, 60, 60);
    doc.setFontSize(8);
    for (let i = 20; i < pdfHeight; i += 40) {
      doc.text("SPACE TOWN RECORDS", pdfWidth - 12, i, { angle: -90 });
    }

    // Logo Superior (Simulado)
    doc.setTextColor(0, 0, 0);
    doc.setFontSize(20);
    doc.setFont("helvetica", "bold");
    doc.text("SPACE", pdfWidth / 2, 20, { align: 'center' });
    doc.text("TOWN", pdfWidth / 2, 28, { align: 'center' });

    // Footer
    doc.setFontSize(9);
    doc.setTextColor(100, 100, 100);
    doc.text("CALI - COLOMBIA", 15, pdfHeight - 15);
    doc.text("315 6307929", 15, pdfHeight - 10);
    doc.text("@SPACETOWNREC", 15, pdfHeight - 5);
    doc.text(pageNumber.toString(), pdfWidth / 2, pdfHeight - 10);
  };

  const drawTable = (doc: jsPDF, startY: number, rows: [string, string][]) => {
    const col1Width = 70;
    const col2Width = 100;
    const rowHeight = 8;
    let currentY = startY;

    rows.forEach(([label, value]) => {
      doc.setDrawColor(200, 200, 200);
      doc.setFillColor(245, 245, 245);
      doc.rect(15, currentY, col1Width, rowHeight, 'FD');
      doc.rect(15 + col1Width, currentY, col2Width, rowHeight, 'D');

      doc.setTextColor(50, 50, 50);
      doc.setFontSize(7);
      doc.setFont("helvetica", "bold");
