  const finishSession = async () => {
    if (!confirm("¿TERMINAR SESIÓN DE ESTUDIO?")) return;
    setIsProcessing(true);
    setProcessingStep("ENVIANDO REPORTE FINAL...");
    const duration = formatTime(elapsedTime);
    try {
