        });
      }
      localStorage.clear();
      setIsProcessing(false);
      setShowFinished(true);
      playInterfaceSound('alert');
    } catch (e) {
      setIsProcessing(false);
    }
  };

  if (showFinished) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-black font-orbitron">
