    doc.setFontSize(10);
    doc.setTextColor(0, 0, 0);
    doc.setFont("helvetica", "bold");
    doc.text("CALI - COLOMBIA", 15, pdfHeight - 15);
    doc.setFont("helvetica", "normal");
    doc.text("315 6307929", 15, pdfHeight - 10);
    doc.text("@SPACETOWNREC", 15, pdfHeight - 5);

    doc.setFontSize(10);
    doc.text(pageNumber.toString(), pdfWidth / 2, pdfHeight - 10);
  };

  const drawTable = (doc: jsPDF, startY: number, rows: [string, string][]) => {
    const col1Width = 70;
    const col2Width = 100;
    const rowHeight = 9;
    let currentY = startY;

    rows.forEach(([label, value]) => {
      doc.setDrawColor(180, 180, 180);
      doc.setFillColor(240, 240, 240); // Fondo gris claro para los labels
      doc.rect(15, currentY, col1Width, rowHeight, 'FD');
      doc.rect(15 + col1Width, currentY, col2Width, rowHeight, 'D');

      doc.setTextColor(0, 0, 0);
      doc.setFontSize(8);
      doc.setFont("helvetica", "bold");
      doc.text(label.toUpperCase(), 18, currentY + 6);

      doc.setFont("helvetica", "normal");
      doc.setTextColor(0, 0, 0);
      doc.setFontSize(9);
      const val = doc.splitTextToSize(value, col2Width - 5);
      doc.text(val, 15 + col1Width + 3, currentY + 6);

      currentY += rowHeight;
    });

    return currentY;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();
