      // PÁGINA 2: EVIDENCIAS
      doc.addPage();
      addPdfDeco(doc, 2);
      doc.setFont("helvetica", "bold");
      doc.text("EVIDENCIA BIOMÉTRICA Y DOCUMENTAL", pdfWidth / 2, 65, { align: 'center' });
