      doc.text("FACE ID - ARTISTA", 20, 135);
      doc.addImage(docFrontData, 'JPEG', 20, 145, 75, 45);
      doc.text("ID ANVERSO", 20, 195);
      doc.addImage(docBackData, 'JPEG', 105, 145, 75, 45);
      doc.text("ID REVERSO", 105, 195);

